defmodule MyApp.Accounts.User do
  use Ecto.Schema
  import Ecto.Changeset

  @allowed_fields [:name, :email, :age, :role]
  @required_fields [:name, :email]

  schema "users" do
    field :name, :string
    field :email, :string
    field :age, :integer
    field :role, :string, default: "user"

    timestamps()
  end

  def changeset(user, params) do
    user
    |> cast(params, @allowed_fields)
    |> validate_required(@required_fields)
    |> validate_format(:email, ~r/^[^\s]+@[^\s]+\.[^\s]+$/, message: "must be a valid email address")
    |> validate_length(:name, min: 1, max: 255)
    |> validate_length(:email, max: 255)
    |> validate_inclusion(:role, ["user", "admin", "moderator"], message: "must be a valid role")
    |> validate_number(:age, greater_than: 0, less_than: 150)
    |> unique_constraint(:email)
    |> sanitize_string_fields()
  end

  defp sanitize_string_fields(changeset) do
    Enum.reduce([:name, :email], changeset, fn field, acc ->
      case get_change(acc, field) do
        nil -> acc
        value when is_binary(value) -> put_change(acc, field, String.trim(value))
        _ -> acc
      end
    end)
  end
end

