  alias MyApp.Repo
  alias MyApp.Accounts.User

  def get_user!(id) when is_integer(id) do
    Repo.get!(User, id)
  end

  def get_user!(id) when is_binary(id) do
    case Integer.parse(id) do
      {int_id, ""} -> Repo.get!(User, int_id)
