defmodule MyAppWeb.UserController do
  use MyAppWeb, :controller

  alias MyApp.Accounts

  action_fallback MyAppWeb.FallbackController

  plug :authorize_update when action in [:update]

  def update(conn, %{"id" => id} = params) do
    user_params = Map.get(params, "user", %{})

    unless is_map(user_params) do
      conn
      |> put_status(:bad_request)
      |> json(%{error: "Invalid parameters"})
      |> halt()
    end

    user = Accounts.get_user!(id)

    user_params = prevent_privilege_escalation(conn, user_params)

    case Accounts.update_user(user, user_params) do
      {:ok, updated_user} ->
        conn
        |> put_status(:ok)
        |> render(:show, user: updated_user)

      {:error, %Ecto.Changeset{} = changeset} ->
        conn
        |> put_status(:unprocessable_entity)
        |> put_view(json: MyAppWeb.ChangesetJSON)
        |> render(:error, changeset: changeset)
    end
  rescue
    Ecto.NoResultsError ->
      conn
      |> put_status(:not_found)
      |> json(%{error: "User not found"})

    Ecto.StaleEntryError ->
      conn
      |> put_status(:conflict)
      |> json(%{error: "User was modified by another process. Please retry."})
  end

  defp authorize_update(conn, _opts) do
    current_user = conn.assigns[:current_user]
    target_user_id = conn.params["id"]

    cond do
      is_nil(current_user) ->
        conn
        |> put_status(:unauthorized)
        |> json(%{error: "Authentication required"})
        |> halt()

      to_string(current_user.id) == to_string(target_user_id) ->
        conn

      current_user.role == "admin" ->
        conn

      true ->
        conn
        |> put_status(:forbidden)
        |> json(%{error: "You are not authorized to update this user"})
        |> halt()
    end
  end

  defp prevent_privilege_escalation(conn, params) do
    current_user = conn.assigns[:current_user]

    if current_user.role != "admin" do
      Map.drop(params, ["role", :role])
    else
      params
    end
  end
end

defmodule MyAppWeb.FallbackController do
  use MyAppWeb, :controller

  def call(conn, {:error, %Ecto.Changeset{} = changeset}) do
    conn
    |> put_status(:unprocessable_entity)
    |> put_view(json: MyAppWeb.ChangesetJSON)
    |> render(:error, changeset: changeset)
  end

  def call(conn, {:error, :not_found}) do
    conn
    |> put_status(:not_found)
    |> json(%{error: "Resource not found"})
  end

  def call(conn, {:error, :unauthorized}) do
    conn
    |> put_status(:unauthorized)
    |> json(%{error: "Unauthorized"})
  end
end

defmodule MyAppWeb.ChangesetJSON do
  def error(%{changeset: changeset}) do
    %{errors: Ecto.Changeset.traverse_errors(changeset, &translate_error/1)}
  end

  defp translate_error({msg, opts}) do
    Enum.reduce(opts, msg, fn {key, value}, acc ->
      String.replace(acc, "%{#{key}}", fn _ -> to_string(value) end)
    end)
  end
end

